No store changes needed — the existing `getSetting(key)` and `setSetting(key, value)` methods work for any key.

**5. Auto-Add Logic**

Add a new method `autoAddMyDayTasks()` to the SQLite `TaskRepository` (`src/main/repositories/TaskRepository.ts`). This is a repository method because it does batch DB operations.

```typescript
autoAddMyDayTasks(userId: string, mode: 'off' | 'due_today' | 'due_today_or_overdue'): string[] {
  if (mode === 'off') return []

  const today = new Date().toISOString().slice(0, 10)
  const dateCondition = mode === 'due_today' 
    ? `date(due_date) = date('now')` 
    : `date(due_date) <= date('now')`

  // Find qualifying tasks: not already in my day, not dismissed today/permanently,
  // not done status, not subtasks, not archived, not templates
  const sql = `
    SELECT t.id FROM tasks t
    JOIN statuses s ON t.status_id = s.id
    WHERE t.owner_id = ?
      AND t.is_archived = 0
      AND t.is_template = 0
      AND t.is_in_my_day = 0
      AND t.parent_id IS NULL
      AND s.is_done = 0
      AND t.due_date IS NOT NULL
      AND ${dateCondition}
      AND (
        t.my_day_dismissed_date IS NULL
        OR (t.my_day_dismissed_date != '9999-12-31' AND t.my_day_dismissed_date != ?)
      )
  `
  const rows = this.db.prepare(sql).all(userId, today) as { id: string }[]

  if (rows.length === 0) return []

  const now = new Date().toISOString()
  const updateStmt = this.db.prepare(
    `UPDATE tasks SET is_in_my_day = 1, my_day_dismissed_date = NULL, updated_at = ? WHERE id = ?`
  )

  const ids: string[] = []
  for (const row of rows) {
    updateStmt.run(now, row.id)
    ids.push(row.id)
  }

  return ids  // Return IDs so caller can trigger sync
}
```

