const migration_N: Migration = {
  version: N,
  up: (db: Database.Database): void => {
    db.exec(`
      ALTER TABLE projects ADD COLUMN auto_archive_enabled INTEGER NOT NULL DEFAULT 0;
      ALTER TABLE projects ADD COLUMN auto_archive_value INTEGER NOT NULL DEFAULT 3;
      ALTER TABLE projects ADD COLUMN auto_archive_unit TEXT NOT NULL DEFAULT 'days';
